mapper.select:
select social_account_id, user_id, provider, provider_user_id, provider_email, is_active, connected_at, disconnected_at
from social_accounts
where social_account_id = #{socialAccountId}

select social_account_id, user_id, provider, provider_user_id, provider_email, is_active, connected_at, disconnected_at
from social_accounts
where provider = #{provider} and provider_user_id = #{providerUserId}

mapper.update:
update social_accounts
set provider_email = #{providerEmail}, is_active = #{isActive}, disconnected_at = #{disconnectedAt}
where social_account_id = #{socialAccountId}
